import{o as e,c as m,C as p}from"./framework.742a1519.js";const t='{"title":"Глава 6","description":"","frontmatter":{"title":"Глава 6","subtitle":"Малини виджайоттара тантра","tags":"malini","date":"2020-10-01T00:00:00.000Z"},"relativePath":"texts/malini-vijayottara/6.md","lastUpdated":1624912770479}',a={},r=p("<p>Шива сказал:</p><p>Теперь поведаю о том, как действуют разновидности Реальности, находящиеся в теле при джнана дикше ..1.</p><p>От подошв стоп и далее, занимая расстояние две ангулы (каждый) размещаются пять элементов. Элемент земли (размещается) в лодыжках и далее вверх по порядку ..2.</p><p>Выше них, (от колен) до бедер находятся шесть уровней, их следует созерцать, начиная с пуруша таттвы и заканчивая шакти таттвой ..3.</p><p>Затем следует сосредоточенно созерцать четыре таттвы, начиная с майи, разместив их на (отрезках, размером ) четыре ангулы (каждая) ..4.</p><p>Затем следует созерцать Шива таттву в виде несравненного огня, проникающего во все таттвы, внутри и снаружи ..5.</p><p>Так, разделяя таттвы, производится ньяса. Теперь описываются пять таттв, которые пребывают в теле ..6.</p><p>Вверх до пупка, начиная от колен, т.е. от таттвы земли, насчитывается шесть уровней. Все они заполнены водой ..7.</p><p>Выше этого (находятся) двадцать два уровня занятых огнем, за ними следуют двенадцать уровней, занятых ветром ..8.</p><p>За акашей следует созерцать всепроникающий высший Покой, который приводится в движение в ритуалах пяти адхв, начиная с шакти. В трех частях, (от колен) до горла проявляется атмататтва. Выше него - видья-таттва и Шива таттва, как (было описано) ранее ..9-10.</p><p>Итак, правило таттв поведано, теперь описывается месторасположение миров (бхуван). Ниже колен следует разместить шестнадцатиградие, начиная с Калагни (Рудры) и заканчивая Вирабхадрой (<em>от колен до стоп</em>). (Они занимают по) одной ангуле (каждый). За ними следует поместить (бхуваны), начиная с Лакулиши и заканчивая Двирандой (<em>от пупка до колен: Лакуллиша, Парабхути, Динди, Мунди, Видхи, Пушкара, Наймиша, Прабхаса, Амареша или Двиранда</em>). Они занимают по три ангулы. За ними (расположен) Чхагаландака и остальные (бхуваны) этой восьмерки Дева йога (<em>Свреху вниз: Бхайрава, Кедара, Махакала, Мадхьямеша, Амратака, Джалпеша, Шришайла, Харишчандра или Чхагаландака, от солнечного сплетения, до пупка</em>), (занимающие) по одной ангуле ..11-13.</p><p>Затем следует созерцать шестиградие, вмещающееся на половине ангулы (<em>анахата чакра</em>). И две четверки и еще раз (две четверки) (<em>т.е. два раза по восемь, снизу вверх: Гая, Курушктра, Накала, Нала, Вималеша, Аттахаса, Махендра, Бхимешвара- воздух, Вастрапада, Рудракоти, Авимукта, Махалья, Гокарна, Бхадракарна, Сварнакша, Стхану- эфир</em>) ..14.</p><p>(Далее сутракара «перепрыгивает» через несколько уровней и идет сверху вниз от миров видьи, описывая канчуки)</p><p>Сверху, от видьи и далее до кала таттвы, возникают один за другим три (уровня) по два (мира в каждом). <em>(Сверху вниз: Панчантака, Шура- видья; Пинга, Джьоти- рага; Самварта, Кродха- кАла</em>) ..15.__</p><p>Над этими покровителями мандал, пребывает занимающая пол- ангулы Трехчастная, Неполная, Вершина (<em>эвфемеизмы йони</em>) ..16.</p><p>Полностью здесь пять (уровней), которые делятся на восемь (миров) (<em>Сверху вниз: Шикшеша, Экавира- калА; Панчантака, Шура- видья; Пинга, Джьоти- рага; Самварта, Кродха- кАла</em>) и еще пять (<em>Сверху вниз: Экашва, Аманта, Аджа, Умапати, Прачанда- нияти</em>). Так их следует различать ..17.</p><p>В правиле разделения адхв следует, как и прежде, созерцать Шиву. Эти уровни разделяются на два вида: на видью и варгу (<em>т.е. ниже видья- таттвы идет видья, выше- варга, т.е. йони</em>) ..18.</p><p>(<em>Далее сутракара снова возвращается вниз и описывает танматры</em>)</p><p>Выслушай об их проникновении в виде танматр. В начале- четыре ангулы (<em>Чакаланда</em>), затем- две (<em>Дравинда</em>) и отдельно- восемь ангул (<em>Макота</em>) ..19.</p><p>(Затем)- десять ангул (<em>Мандалешвара</em>), три по одной (<em>Каланджара, Шанкукарна, Стхулешвара</em>), одна по пятнадцать ангул (<em>Стхалешвара</em>), над этими четырьмя (<em>уровнями- танматры, кармендрии, джнянендрии, аханкара</em>)- великая проникающая девятка (<em>Снизу вверх: Пишача, Ракшаса, Ракшас, Якша, Гандхарва, Аиндра, Саумья, Праджеша, Брахма- миры буддхи</em>) ..20.</p><p>(Далее сутракара пропускает восемь миров Пракрити-таттвы- Акрита, Крита, Бхайрава, Брахма, Вайшнава, Кумара, Аума, Шрикантха)</p><p>Девятнадцать (и один) миров именуются вьяпти (<em>по- видимому, повреждение в тексте, т. к. в других источниках и далее по тексту миров вьяпти, или пралаякала, от майа- до пракрити- таттвы насчитывается двадцать)</em>. Вначале три уровня по две ангулы каждый (<em>Вама, Бхима, Угра</em>) ..21.</p><p>Затем идут четыре уровня по семь ангул (<em>Иша, Бхава, Ишана</em>), затем- один по десять ангул (<em>Экавира, перечислены семь миров пуруша таттвы</em>), два уровня по две ангулы (<em>Прачанда, Умапати</em>) и один по шесть (<em>Аджа</em>) ..22.</p><p>Другие два по двенадцать ангул (<em>Аманта, Экашва- перечислены пять миров нияти- таттвы</em>), две по пять ангул (<em>Кродха, Самварта -два мира кАла таттвы</em>), затем два по два уровня по четыре (ангулы) (<em>Джьоти Пинга- рага таттва, Шура, Панчантака- видья таттва</em>), затем две по две (<em>Экавира, Шикшеша- калА таттва</em>) ..23.</p><p>Это именуется уровнями вьяпти. Поведана низшее правило (апара), теперь услышь о промежуточном (параапара) ..24.</p><p>Как и раньше таттва земли- четыре ангулы, другие вплоть до буддхи, следует обозначить по половине ангулы ..25.</p><p>Прадхану (Пракрити) на три ангулы, выше (пуруша) следует выделить как и раньше (т.е., половина ангулы). Еще выше (нияти) (следует выделить) как землю, (на четыре ангулы) еще выше (кАла) на три ангулы. Три уровня над нею - (как) прадхана (три ангулы), оставшееся- как и прежде (половина ангулы), ему следует предаться. (Так) называются два вида варн, шести уровней ..26-27.</p><p>Таким образом постигается путь таттв, пады, мантры, калы и прочего согласно изначальной сутре ..28.</p><p>Так осуществляются, путем названной триады, таттва и варна (адхва). Так над элементами тела осуществляется посвящение Учителем, в образе Шивы, дающее все плоды ..29. [small]Такова в священной «Малиивиджайоттара тантре» шестая глава (именуемая) «Путь тела».[/small]</p>",29);a.render=function(p,t,a,i,l,_){return e(),m("div",null,[r])};export default a;export{t as __pageData};
